/* about-ecosystem-3col-01 section (for sections.css) */
.l-about {
    padding: 6vw;
    background-color: #f5eac1;
}

.l-about .c-container {
    width: min(100%, 1400px);
    margin-right: auto;
    margin-left: auto;
}

.c-content-about-ecosystem-3col-01 {
    display: grid;
    gap: clamp(12px, 1.5vw, 22px);
}

.c-content-about-ecosystem-3col-01__head {
    display: grid;
    gap: 16px;
}

.c-content-about-ecosystem-3col-01__eyebrow {
    margin: 0;
    color: #000;
    font-size: 16px;
    font-weight: 700;
    line-height: 1.3;
}

.c-content-about-ecosystem-3col-01__title {
    margin: 0;
    color: #000;
    font-size: clamp(42px, 6vw, 96px);
    font-weight: 700;
    line-height: 0.9;
}

.c-content-about-ecosystem-3col-01__body {
    display: grid;
    gap: clamp(18px, 3vw, 40px);
}

.c-content-about-ecosystem-3col-01__grid-top {
    display: grid;
    grid-template-columns: 33.38% 33% 33.62%;
    gap: 3vw;
}

.c-content-about-ecosystem-3col-01__col-text {
    display: grid;
    gap: 18px;
}

.c-content-about-ecosystem-3col-01__text,
.c-content-about-ecosystem-3col-01__text-note {
    margin: 0;
    color: #000;
    font-size: 17px;
    line-height: 1.75;
}

.c-content-about-ecosystem-3col-01__col-media-a {
    padding-top: 2vw;
}

.c-content-about-ecosystem-3col-01__media-a,
.c-content-about-ecosystem-3col-01__media-b,
.c-content-about-ecosystem-3col-01__media-c {
    margin: 0;
}

.c-content-about-ecosystem-3col-01__image-a,
.c-content-about-ecosystem-3col-01__image-b,
.c-content-about-ecosystem-3col-01__image-c {
    display: block;
    width: 100%;
    height: auto;
}

.c-content-about-ecosystem-3col-01__grid-bottom {
    display: grid;
    grid-template-columns: 69% 33%;
    gap: 3vw;
}

.c-content-about-ecosystem-3col-01__col-note {
    display: flex;
    align-items: center;
    padding-top: 2vw;
}

.c-content-about-ecosystem-3col-01--compact .c-content-about-ecosystem-3col-01__title {
    font-size: clamp(36px, 5vw, 72px);
}

.c-content-about-ecosystem-3col-01--text-large .c-content-about-ecosystem-3col-01__text,
.c-content-about-ecosystem-3col-01--text-large .c-content-about-ecosystem-3col-01__text-note {
    font-size: 19px;
}

@media (max-width: 960px) {
    .c-content-about-ecosystem-3col-01__grid-top,
    .c-content-about-ecosystem-3col-01__grid-bottom {
        grid-template-columns: 1fr;
        gap: 24px;
    }

    .c-content-about-ecosystem-3col-01__col-media-a,
    .c-content-about-ecosystem-3col-01__col-note {
        padding-top: 0;
    }
}

/* about section (for sections.css) */
.l-about {
    padding: 96px 0;
    overflow: hidden;
}

.l-about .c-container {
    width: min(100% - 40px, 1200px);
    margin-right: auto;
    margin-left: auto;
}

.c-content-about-collage-01 {
    position: relative;
    display: grid;
    grid-template-columns: minmax(0, 1.05fr) minmax(0, 0.95fr);
    gap: clamp(24px, 4vw, 72px);
    align-items: center;
    padding: clamp(48px, 6vw, 88px) clamp(24px, 5vw, 72px);
}

.c-content-about-collage-01--bg-gray {
    background-color: #efefef;
}

.c-content-about-collage-01--full-width {
    width: 100vw;
    margin-left: calc(50% - 50vw);
    margin-right: calc(50% - 50vw);
}

.c-content-about-collage-01__media {
    position: relative;
    width: min(100%, 720px);
    margin-bottom: clamp(32px, 5vw, 70px);
    z-index: 1;
}

.c-content-about-collage-01__image {
    display: block;
    width: 100%;
    aspect-ratio: 4 / 3;
    object-fit: cover;
    object-position: center;
    box-shadow: 0 16px 34px rgba(0, 0, 0, 0.12);
}

.c-content-about-collage-01__image--primary {
    position: relative;
    z-index: 1;
    object-position: 22% 52%;
}

.c-content-about-collage-01__image--secondary {
    position: absolute;
    right: -4%;
    bottom: -18%;
    width: clamp(180px, 44%, 300px);
    aspect-ratio: 3 / 4;
    z-index: 2;
    object-position: 65% 78%;
}

.c-content-about-collage-01__eyebrow {
    margin: 0;
    color: #1f8ecf;
    font-size: clamp(34px, 5.2vw, 62px);
    font-weight: 700;
    letter-spacing: 0.06em;
    line-height: 1;
}

.c-content-about-collage-01__title {
    margin: 12px 0 0;
    color: #2b2b2b;
    font-size: clamp(22px, 2.1vw, 34px);
    font-weight: 700;
    line-height: 1.4;
}

.c-content-about-collage-01__title--underline {
    position: relative;
    padding-bottom: 18px;
}

.c-content-about-collage-01__title--underline::after {
    content: "";
    display: block;
    width: 74px;
    height: 2px;
    margin-top: 14px;
    background-color: #1f8ecf;
}

.c-content-about-collage-01__lead {
    margin: 30px 0 0;
    color: #444;
    font-size: clamp(15px, 1.45vw, 20px);
    line-height: 2.1;
}

.c-content-about-collage-01__button {
    display: inline-flex;
    justify-content: center;
    align-items: center;
    min-width: 280px;
    margin-top: 34px;
    padding: 16px 28px;
    color: #fff;
    font-size: 16px;
    font-weight: 700;
    line-height: 1;
    text-decoration: none;
    background-color: #1f8ecf;
    transition: opacity 0.2s ease;
}

.c-content-about-collage-01__button:hover {
    opacity: 0.88;
}

.c-content-about-collage-01__decor {
    position: absolute;
    right: 0;
    bottom: 0;
    left: 0;
    height: clamp(120px, 18vw, 210px);
    background-image: radial-gradient(circle, rgba(0, 0, 0, 0.11) 1px, transparent 1px);
    background-size: 8px 8px;
    opacity: 0.28;
    pointer-events: none;
}

.c-content-about-collage-01--reverse {
    grid-template-columns: minmax(0, 0.95fr) minmax(0, 1.05fr);
}

.c-content-about-collage-01--reverse .c-content-about-collage-01__media {
    order: 2;
}

.c-content-about-collage-01--reverse > div:nth-child(2) {
    order: 1;
}

@media (max-width: 900px) {
    .c-content-about-collage-01 {
        grid-template-columns: 1fr;
    }

    .c-content-about-collage-01__media {
        width: min(100%, 640px);
        margin-right: auto;
        margin-left: auto;
    }

    .c-content-about-collage-01__image--secondary {
        right: 4%;
        bottom: -14%;
        width: clamp(150px, 40vw, 230px);
    }

    .c-content-about-collage-01__lead {
        line-height: 1.9;
    }

    .c-content-about-collage-01__button {
        min-width: 220px;
    }

    .c-content-about-collage-01--reverse .c-content-about-collage-01__media,
    .c-content-about-collage-01--reverse > div:nth-child(2) {
        order: initial;
    }
}

